(function(){
  "use strict";
  const EXP2={"es":["Aviso Legal","Responsable del Sitio Web","En cumplimiento con lo establecido en el Reglamento General de Protección de Datos (RGPD) y la Ley Orgánica de Protección de Datos Personales y Garantía de los Derechos Digitales (LOPDGDD), se informa que el responsable del sitio web mycontacts.cloud (en adelante, el 'Sitio Web') es:","Responsable: ","Domicilio: ","Correo electrónico: ","Finalidad del Sitio Web","El Sitio Web tiene como finalidad proporcionar información sobre la aplicación web My Contacts.","Recogida y Tratamiento de Datos Personales","El responsable del Sitio Web cumple con las directrices del RGPD y la LOPDGDD en cuanto a la protección de los datos personales y garantiza el correcto uso y tratamiento de los datos personales del usuario. Para más información sobre cómo recopilamos, utilizamos y protegemos tus datos personales, consulta nuestra Política de Privacidad.","Propiedad Intelectual e Industrial","Todos los derechos de propiedad intelectual e industrial del Sitio Web y sus contenidos, incluyendo textos, imágenes, diseños, logotipos, software, nombres comerciales, marcas, etc., pertenecen al responsable del Sitio Web o a terceros que han autorizado su uso. Queda prohibida cualquier forma de reproducción, distribución, comunicación pública, transformación o cualquier otra actividad que se pueda realizar con los contenidos del Sitio Web, salvo autorización expresa por escrito del responsable del Sitio Web.","Limitación de Responsabilidad","El responsable del Sitio Web no se hace responsable de los errores u omisiones en la información publicada en el Sitio Web, ni de los posibles daños derivados del uso del Sitio Web. Asimismo, el responsable del Sitio Web no se hace responsable de los contenidos de los sitios web enlazados desde el Sitio Web.","Legislación y Jurisdicción Aplicable","Este Aviso Legal se rige por la legislación española vigente. Cualquier controversia o conflicto que pueda surgir del acceso o uso del Sitio Web se someterá a la jurisdicción de los tribunales de Valencia (España), renunciando expresamente a cualquier otro fuero que pudiera corresponder.","Contacto","Si tienes alguna pregunta o comentario sobre este Aviso Legal, puedes ponerte en contacto con nosotros a través de la siguiente dirección de correo electrónico: info@mycontacts.cloud.","Política de Privacidad","Responsable del Tratamiento de Datos","En cumplimiento con lo establecido en el Reglamento General de Protección de Datos (RGPD) y la Ley Orgánica de Protección de Datos Personales y Garantía de los Derechos Digitales (LOPDGDD), se informa que el responsable del tratamiento de los datos personales recogidos a través del sitio web mycontacts.cloud (en adelante, el 'Sitio Web') es:","Responsable: ","Domicilio: ","Correo electrónico: ","Recogida y Tratamiento de Datos Personales","El responsable del tratamiento de los datos personales cumple con las directrices del RGPD y la LOPDGDD en cuanto a la protección de los datos personales de los usuarios y garantiza el correcto uso y tratamiento de los mismos. Los datos personales recogidos a través del Sitio Web serán tratados de forma confidencial y no se utilizarán para fines distintos a los especificados en esta Política de Privacidad, salvo que se obtenga el consentimiento previo del usuario.","Finalidad del Tratamiento de Datos","Los datos personales proporcionados por los usuarios a través del Sitio Web serán utilizados con la finalidad de:","Responder a consultas y solicitudes realizadas a través del formulario de contacto y haya concedido el consentimiento correspondiente","Enviar información sobre la app My Contacts siempre y cuando se haya suscrito a la newsletter y haya otorgado el consentimiento correspondiente","Gestionar y mantener la relación comercial con los usuarios","Realizar análisis estadísticos y estudios de mercado","Seguridad de los Datos Personales","El responsable del tratamiento de los datos personales ha adoptado las medidas técnicas y organizativas necesarias para garantizar la seguridad de los datos personales y evitar su alteración, pérdida, tratamiento o acceso no autorizado, teniendo en cuenta el estado de la tecnología, la naturaleza de los datos almacenados y los riesgos a los que están expuestos. Sin embargo, el responsable del tratamiento no puede garantizar la absoluta seguridad de los datos transmitidos a través de Internet.","Derechos del Usuario","El usuario tiene derecho a:","Acceder a sus datos personales y solicitar información sobre cómo se están tratando","Rectificar los datos personales inexactos o incompletos","Suprimir sus datos personales cuando ya no sean necesarios para los fines para los que fueron recogidos","Limitar el tratamiento de sus datos personales en determinadas circunstancias","Portar sus datos personales a otro responsable del tratamiento en un formato estructurado y de uso común","Oponerse al tratamiento de sus datos personales en determinadas circunstancias y por motivos relacionados con su situación particular","El ejercicio de estos derechos podrá llevarse a cabo a través de los datos de contacto proporcionados en esta Política de Privacidad.","Enlaces a Sitios Web de Terceros","El Sitio Web puede contener enlaces a sitios web de terceros. El responsable del tratamiento no se hace responsable de las prácticas de privacidad ni del contenido de dichos sitios web. Se recomienda a los usuarios leer las políticas de privacidad de los sitios web de terceros antes de proporcionar cualquier información personal.","Modificaciones de la Política de Privacidad","El responsable del tratamiento se reserva el derecho de modificar esta Política de Privacidad en cualquier momento. Se recomienda a los usuarios revisar periódicamente esta página para estar informados de las actualizaciones.","Jurisdicción y Ley Aplicable","Esta Política de Privacidad se regirá e interpretará de acuerdo con la legislación española. Cualquier controversia que pueda surgir en relación con la interpretación o aplicación de esta Política de Privacidad será sometida a los tribunales de Valencia (España).","Contacto","Si tienes alguna pregunta o comentario sobre esta Política de Privacidad, puedes ponerte en contacto con nosotros a través de la siguiente dirección de correo electrónico: info@mycontacts.cloud.","Política de Cookies","En cumplimiento con lo establecido en el artículo 22.2 de la Ley de Servicios de la Sociedad de la Información y Comercio Electrónico (LSSI), se informa que este sitio web utiliza cookies propias para mejorar la experiencia de navegación y ofrecer contenido personalizado.","¿Qué son las cookies?","Una cookie o tecnología similar es un pequeño archivo de texto que se almacena en el dispositivo del usuario cuando visita un sitio web. Las cookies permiten que el sitio web reconozca al usuario, recuerde sus preferencias y proporcione una experiencia personalizada.","¿Qué tipos de cookies utiliza este sitio web?","Este sitio web utiliza las siguientes cookies:","Cookies necesarias","Estas cookies son esenciales para el funcionamiento del sitio web. Generalmente, se establecen solo en respuesta a acciones realizadas por el usuario, como establecer preferencias de privacidad. El usuario puede configurar su navegador para bloquear o alertar sobre estas cookies, pero algunas partes del sitio no funcionarán. Estas cookies no almacenan ninguna información de identificación personal.","Cookies funcionales","Estas cookies permiten que el sitio web recuerde las elecciones que el usuario hace (como por ejemplo su idioma) y proporciona características mejoradas y más personalizadas. También sirven para almacenar temporalmente sus datos personales rellenados en el formulario de contacto y el formulario de suscripción a la newsletter.","¿Cómo puedo gestionar las cookies?","El usuario tiene la opción de aceptar o rechazar cada tipo de cookies desde el enlace de 'Configuración de cookies', que encontrará al final de la página web. El usuario también puede gestionar las cookies a través de la configuración de su navegador. En la mayoría de los navegadores web, es posible permitir, bloquear o eliminar las cookies instaladas en el dispositivo. Cada navegador tiene sus propias instrucciones sobre cómo gestionar las cookies. A continuación, se proporcionan enlaces a la documentación de los navegadores más comunes:","Modificaciones de la Política de Cookies","El responsable del sitio web se reserva el derecho de modificar esta Política de Cookies en cualquier momento. Se recomienda al usuario revisar periódicamente esta página para estar informado de los cambios y actualizaciones.","Contacto","Si tienes alguna pregunta o comentario sobre esta Política de Cookies, puedes ponerte en contacto con nosotros a través de la siguiente dirección de correo electrónico: info@mycontacts.cloud.","He leído y aceptado la ","¡Gracias por unirte!"],"en":["Legal Notice","Responsible for the Website","In compliance with the provisions of the General Data Protection Regulation (GDPR) and the Organic Law on the Protection of Personal Data and Guarantee of Digital Rights (LOPDGDD), it is informed that the responsible party for the website mycontacts.cloud (hereinafter, the 'Website') is:","Responsible: ","Address: ","Email: ","Purpose of the Website","The website aims to provide information about the web application My Contacts.","Collection and Processing of Personal Data","The responsible party for the Website complies with the guidelines of the GDPR and the LOPDGDD regarding the protection of personal data and guarantees the correct use and processing of the user's personal data. For more information on how we collect, use, and protect your personal data, please refer to our Privacy Policy.","Intellectual and Industrial Property","All intellectual and industrial property rights of the Website and its contents, including texts, images, designs, logos, software, trade names, trademarks, etc., belong to the responsible party for the Website or third parties who have authorized their use. Any form of reproduction, distribution, public communication, transformation, or any other activity that may be carried out with the contents of the Website is prohibited, except with the express written authorization of the responsible party for the Website.","Limitation of Liability","The responsible party for the Website is not responsible for errors or omissions in the information published on the Website, nor for any possible damages derived from the use of the Website. Likewise, the responsible party for the Website is not responsible for the contents of websites linked from the Website.","Applicable Legislation and Jurisdiction","This Legal Notice is governed by the current Spanish legislation. Any controversy or conflict that may arise from the access or use of the Website will be subject to the jurisdiction of the courts of Valencia (Spain), expressly waiving any other jurisdiction that may correspond.","Contact","If you have any questions or comments regarding this Legal Notice, you can contact us at the following email address: info@mycontacts.cloud.","Privacy Policy","Data Controller","In compliance with the provisions of the General Data Protection Regulation (GDPR) and the Organic Law on the Protection of Personal Data and Guarantee of Digital Rights (LOPDGDD), it is informed that the data controller for the personal data collected through the website mycontacts.cloud (hereinafter, the 'Website') is:","Controller:","Address:","Email:","Collection and Processing of Personal Data","The data controller complies with the guidelines of the GDPR and the LOPDGDD regarding the protection of users' personal data and guarantees the correct use and processing of such data. The personal data collected through the Website will be treated confidentially and will not be used for purposes other than those specified in this Privacy Policy, unless the user gives prior consent.","Purpose of Data Processing","The personal data provided by users through the Website will be used for the following purposes:","Responding to inquiries and requests made through the contact form, with the corresponding consent","Sending information about the My Contacts app, provided the user has subscribed to the newsletter and given the corresponding consent","Managing and maintaining the business relationship with users","Conducting statistical analysis and market studies","Security of Personal Data","The data controller has implemented the necessary technical and organizational measures to ensure the security of personal data and to prevent its alteration, loss, unauthorized access, or processing, taking into account the state of the technology, the nature of the stored data, and the risks to which they are exposed. However, the data controller cannot guarantee the absolute security of data transmitted over the Internet.","User Rights","The user has the right to:","Access their personal data and request information on how it is being processed","Rectify inaccurate or incomplete personal data","Delete their personal data when it is no longer necessary for the purposes for which it was collected","Restrict the processing of their personal data in certain circumstances","Port their personal data to another data controller in a structured, commonly used, and machine-readable format","Object to the processing of their personal data in certain circumstances and on grounds relating to their particular situation","These rights can be exercised through the contact information provided in this Privacy Policy.","Links to Third-Party Websites","The Website may contain links to third-party websites. The data controller is not responsible for the privacy practices or content of such websites. Users are advised to read the privacy policies of third-party websites before providing any personal information.","Modifications to the Privacy Policy","The data controller reserves the right to modify this Privacy Policy at any time. Users are advised to periodically review this page for updates.","Jurisdiction and Applicable Law","This Privacy Policy shall be governed and interpreted in accordance with Spanish legislation. Any dispute arising from the interpretation or application of this Privacy Policy shall be submitted to the courts of Valencia (Spain).","Contact","If you have any questions or comments about this Privacy Policy, you can contact us at the following email address: info@mycontacts.cloud.","Cookie Policy","In compliance with the provisions of article 22.2 of the Law on Information Society Services and Electronic Commerce (LSSI), it is informed that this website uses its own cookies to improve the browsing experience and provide personalized content.","What are cookies?","A cookie or similar technology is a small text file that is stored on the user's device when they visit a website. Cookies allow the website to recognize the user, remember their preferences, and provide a personalized experience.","What types of cookies does this website use?","This website uses the following cookies:","Necessary cookies","These cookies are essential for the functioning of the website. They are generally set in response to actions taken by the user, such as privacy preferences. The user can configure their browser to block or alert about these cookies, but some parts of the site may not work. These cookies do not store any personally identifiable information.","Functional cookies","These cookies allow the website to remember choices made by the user (such as language) and provide enhanced and more personalized features. They also serve to temporarily store the user's personal data filled in the contact form and the newsletter subscription form.","How can I manage cookies?","The user has the option to accept or reject each type of cookie from the 'Cookie Settings' link, which can be found at the bottom of the web page. The user can also manage cookies through their browser settings. In most web browsers, it is possible to allow, block, or delete cookies installed on the device. Each browser has its own instructions on how to manage cookies. Below are links to documentation for the most common browsers:","Changes to the Cookie Policy","The website owner reserves the right to modify this Cookie Policy at any time. It is recommended that the user periodically review this page to stay informed of changes and updates.","Contact","If you have any questions or comments about this Cookie Policy, you can contact us at the following email address: info@mycontacts.cloud.","I have read and accepted the ","Thank you for joining!"],"fr":["Mention Légale","Responsable du Site Web","Conformément aux dispositions du Règlement général sur la protection des données (RGPD) et de la Loi organique sur la protection des données personnelles et la garantie des droits numériques (LOPDGDD), il est informé que le responsable du site web mycontacts.cloud (ci-après, le 'Site Web') est :","Responsable: ","Adresse: ","E-mail: ","Objectif du Site Web","Le site web a pour but de fournir des informations sur l'application web My Contacts.","Collecte et Traitement des Données Personnelles","Le responsable du Site Web se conforme aux directives du RGPD et de la LOPDGDD en matière de protection des données personnelles et garantit l'utilisation correcte et le traitement des données personnelles de l'utilisateur. Pour plus d'informations sur la façon dont nous collectons, utilisons et protégeons vos données personnelles, veuillez consulter notre Politique de confidentialité.","Propriété Intellectuelle et Industrielle","Tous les droits de propriété intellectuelle et industrielle du Site Web et de ses contenus, y compris les textes, images, designs, logos, logiciels, noms commerciaux, marques, etc., appartiennent au responsable du Site Web ou à des tiers ayant autorisé leur utilisation. Toute forme de reproduction, distribution, communication au public, transformation ou toute autre activité pouvant être réalisée avec les contenus du Site Web est interdite, sauf autorisation expresse écrite du responsable du Site Web.","Limitation de Responsabilité","Le responsable du Site Web n'est pas responsable des erreurs ou omissions dans les informations publiées sur le Site Web, ni des éventuels dommages découlant de l'utilisation du Site Web. De même, le responsable du Site Web n'est pas responsable du contenu des sites Web liés depuis le Site Web.","Législation et Juridiction Applicables","Ces mentions légales sont régies par la législation espagnole en vigueur. Toute controverse ou litige pouvant découler de l'accès ou de l'utilisation du Site Web sera soumis à la juridiction des tribunaux de Valencia (Espagne), renonçant expressément à toute autre juridiction qui pourrait correspondre.","Contact","Si vous avez des questions ou des commentaires concernant ces mentions légales, vous pouvez nous contacter à l'adresse e-mail suivante : info@mycontacts.cloud.","Politique de confidentialité","Responsable du traitement des données","Conformément aux dispositions du Règlement général sur la protection des données (RGPD) et de la Loi organique sur la protection des données personnelles et la garantie des droits numériques (LOPDGDD), il est informé que le responsable du traitement des données personnelles collectées via le site web mycontacts.cloud (ci-après dénommé le 'Site Web') est :","Responsable :","Adresse :","E-mail :","Collecte et traitement des données personnelles","Le responsable du traitement des données personnelles se conforme aux directives du RGPD et de la LOPDGDD en matière de protection des données personnelles des utilisateurs et garantit l'utilisation et le traitement corrects de ces données. Les données personnelles collectées via le Site Web seront traitées de manière confidentielle et ne seront pas utilisées à d'autres fins que celles spécifiées dans cette politique de confidentialité, sauf consentement préalable de l'utilisateur.","Objectif du traitement des données","Les données personnelles fournies par les utilisateurs via le Site Web seront utilisées dans les buts suivants :","Répondre aux demandes et requêtes formulées via le formulaire de contact et ayant donné leur consentement correspondant","Envoyer des informations sur l'application My Contacts, à condition que l'utilisateur se soit abonné à la newsletter et ait donné son consentement correspondant","Gérer et maintenir la relation commerciale avec les utilisateurs","Réaliser des analyses statistiques et des études de marché","Sécurité des données personnelles","Le responsable du traitement des données personnelles a mis en place les mesures techniques et organisationnelles nécessaires pour garantir la sécurité des données personnelles et prévenir leur altération, leur perte, leur accès non autorisé ou leur traitement, en tenant compte de l'état de la technologie, de la nature des données stockées et des risques auxquels elles sont exposées. Cependant, le responsable du traitement ne peut garantir une sécurité absolue des données transmises via Internet.","Droits de l'utilisateur","L'utilisateur dispose des droits suivants :","Accéder à ses données personnelles et demander des informations sur leur traitement","Rectifier les données personnelles inexactes ou incomplètes","Supprimer ses données personnelles lorsqu'elles ne sont plus nécessaires aux fins pour lesquelles elles ont été collectées","Limiter le traitement de ses données personnelles dans certaines circonstances","Transférer ses données personnelles à un autre responsable de traitement dans un format structuré, couramment utilisé et lisible par machine","S'opposer au traitement de ses données personnelles dans certaines circonstances et pour des motifs liés à sa situation particulière","Ces droits peuvent être exercés via les coordonnées fournies dans cette politique de confidentialité.","Liens vers des sites web de tiers","Le Site Web peut contenir des liens vers des sites web de tiers. Le responsable du traitement des données n'est pas responsable des pratiques de confidentialité ni du contenu de ces sites web. Il est recommandé aux utilisateurs de lire les politiques de confidentialité des sites web de tiers avant de fournir des informations personnelles.","Modifications de la politique de confidentialité","Le responsable du traitement des données se réserve le droit de modifier cette politique de confidentialité à tout moment. Il est recommandé aux utilisateurs de consulter régulièrement cette page pour obtenir les mises à jour.","Compétence juridictionnelle et loi applicable","Cette politique de confidentialité est régie et interprétée conformément à la législation espagnole. Tout litige découlant de l'interprétation ou de l'application de cette politique de confidentialité sera soumis aux tribunaux de Valencia (Espagne).","Contact","Si vous avez des questions ou des commentaires sur cette politique de confidentialité, vous pouvez nous contacter à l'adresse e-mail suivante : info@mycontacts.cloud.","Politique des cookies","Conformément aux dispositions de l'article 22.2 de la Loi sur les services de la société de l'information et du commerce électronique (LSSI), il est précisé que ce site web utilise ses propres cookies pour améliorer l'expérience de navigation et fournir un contenu personnalisé.","Qu'est-ce que les cookies?","Un cookie ou une technologie similaire est un petit fichier texte stocké sur l'appareil de l'utilisateur lorsqu'il visite un site web. Les cookies permettent au site web de reconnaître l'utilisateur, de mémoriser ses préférences et de fournir une expérience personnalisée.","Quels types de cookies ce site web utilise-t-il?","Ce site web utilise les cookies suivants:","Cookies nécessaires","Ces cookies sont indispensables au fonctionnement du site web. Ils sont généralement définis en réponse à des actions effectuées par l'utilisateur, telles que les préférences de confidentialité. L'utilisateur peut configurer son navigateur pour bloquer ou alerter sur ces cookies, mais certaines parties du site peuvent ne pas fonctionner. Ces cookies ne stockent aucune information d'identification personnelle.","Cookies fonctionnels","Ces cookies permettent au site web de mémoriser les choix effectués par l'utilisateur (comme la langue) et de fournir des fonctionnalités améliorées et plus personnalisées. Ils servent également à stocker temporairement les données personnel les renseignées par l'utilisateur dans le formulaire de contact et le formulaire d'abonnement à la newsletter.","Comment puis-je gérer les cookies?","L'utilisateur a la possibilité d'accepter ou de refuser chaque type de cookie à partir du lien 'Paramètres des cookies', qui se trouve en bas de la page web. L'utilisateur peut également gérer les cookies via les paramètres de son navigateur. Dans la plupart des navigateurs web, il est possible d'autoriser, de bloquer ou de supprimer les cookies installés sur l'appareil. Chaque navigateur a ses propres instructions sur la gestion des cookies. Ci-dessous, vous trouverez des liens vers la documentation des navigateurs les plus courants :","Modifications de la politique des cookies","Le responsable du site web se réserve le droit de modifier cette politique des cookies à tout moment. Il est recommandé à l'utilisateur de consulter régulièrement cette page pour être informé des changements et mises à jour.","Contact","Si vous avez des questions ou des commentaires concernant cette politique des cookies, vous pouvez nous contacter à l'adresse e-mail suivante : info@mycontacts.cloud.","J'ai lu et accepté la ","Merci de nous rejoindre !"],"pt":["Aviso Legal","Responsável pelo Site","Em conformidade com as disposições do Regulamento Geral de Proteção de Dados (RGPD) e da Lei Orgânica de Proteção de Dados Pessoais e Garantia dos Direitos Digitais (LOPDGDD), informa-se que o responsável pelo site mycontacts.cloud (doravante denominado 'Site') é:","Responsável: ","Endereço: ","E-mail: ","Objetivo do Site","O site tem como objetivo fornecer informações sobre o aplicativo web My Contacts.","Coleta e Tratamento de Dados Pessoais","O responsável pelo Site cumpre as diretrizes do RGPD e da LOPDGDD no que diz respeito à proteção de dados pessoais e garante o uso correto e o tratamento dos dados pessoais do usuário. Para obter mais informações sobre como coletamos, usamos e protegemos seus dados pessoais, consulte nossa Política de Privacidade.","Propriedade Intelectual e Industrial","Todos os direitos de propriedade intelectual e industrial do Site e de seus conteúdos, incluindo textos, imagens, designs, logotipos, software, nomes comerciais, marcas, etc., pertencem ao responsável pelo Site ou a terceiros que autorizaram seu uso. Fica proibida qualquer forma de reprodução, distribuição, comunicação pública, transformação ou qualquer outra atividade que possa ser realizada com os conteúdos do Site, exceto com a autorização expressa por escrito do responsável pelo Site.","Limitação de Responsabilidade","O responsável pelo Site não se responsabiliza por erros ou omissões nas informações publicadas no Site, nem pelos eventuais danos decorrentes do uso do Site. Da mesma forma, o responsável pelo Site não se responsabiliza pelos conteúdos dos sites vinculados ao Site.","Legislação e Jurisdição Aplicáveis","Este Aviso Legal é regido pela legislação espanhola em vigor. Qualquer controvérsia ou conflito decorrente do acesso ou uso do Site será submetido à jurisdição dos tribunais de Valencia (Espanha), renunciando expressamente a qualquer outra jurisdição que possa corresponder.","Contato","Se tiver alguma pergunta ou comentário sobre este Aviso Legal, você pode entrar em contato conosco pelo seguinte endereço de e-mail: info@mycontacts.cloud.","Política de Privacidade","Responsável pelo Tratamento de Dados","Em conformidade com as disposições do Regulamento Geral de Proteção de Dados (RGPD) e da Lei Orgânica de Proteção de Dados Pessoais e Garantia dos Direitos Digitais (LOPDGDD), informa-se que o responsável pelo tratamento dos dados pessoais coletados por meio do site mycontacts.cloud (doravante, o 'Site') é:","Responsável:","Endereço:","E-mail:","Coleta e Tratamento de Dados Pessoais","O responsável pelo tratamento de dados pessoais cumpre as diretrizes do RGPD e da LOPDGDD no que diz respeito à proteção dos dados pessoais dos usuários e garante o uso e tratamento corretos desses dados. Os dados pessoais coletados por meio do Site serão tratados de forma confidencial e não serão utilizados para fins diferentes dos especificados nesta Política de Privacidade, salvo consentimento prévio do usuário.","Finalidade do Tratamento de Dados","Os dados pessoais fornecidos pelos usuários por meio do Site serão utilizados com as seguintes finalidades:","Responder a consultas e solicitações feitas por meio do formulário de contato, com o consentimento correspondente","Enviar informações sobre o aplicativo My Contacts, desde que o usuário tenha se inscrito na newsletter e dado o consentimento correspondente","Gerenciar e manter o relacionamento comercial com os usuários","Realizar análises estatísticas e estudos de mercado","Segurança dos Dados Pessoais","O responsável pelo tratamento de dados pessoais implementou as medidas técnicas e organizacionais necessárias para garantir a segurança dos dados pessoais e evitar sua alteração, perda, acesso não autorizado ou tratamento, levando em consideração o estado da tecnologia, a natureza dos dados armazenados e os riscos aos quais estão expostos. No entanto, o responsável pelo tratamento não pode garantir a segurança absoluta dos dados transmitidos pela Internet.","Direitos do Usuário","O usuário tem o direito de:","Acessar seus dados pessoais e solicitar informações sobre como eles estão sendo tratados","Retificar dados pessoais imprecisos ou incompletos","Excluir seus dados pessoais quando não forem mais necessários para os fins para os quais foram coletados","Limitar o tratamento de seus dados pessoais em determinadas circunstâncias","Transferir seus dados pessoais para outro responsável pelo tratamento, em um formato estruturado, de uso comum e legível por máquina","Opor-se ao tratamento de seus dados pessoais em determinadas circunstâncias e por motivos relacionados à sua situação particular","Esses direitos podem ser exercidos por meio dos dados de contato fornecidos nesta Política de Privacidade.","Links para Sites de Terceiros","O Site pode conter links para sites de terceiros. O responsável pelo tratamento não se responsabiliza pelas práticas de privacidade ou pelo conteúdo desses sites. Recomenda-se aos usuários que leiam as políticas de privacidade dos sites de terceiros antes de fornecer qualquer informação pessoal.","Modificações na Política de Privacidade","O responsável pelo tratamento reserva-se o direito de modificar esta Política de Privacidade a qualquer momento. Recomenda-se aos usuários que revisem periodicamente esta página para se manterem atualizados.","Jurisdição e Lei Aplicável","Esta Política de Privacidade será regida e interpretada de acordo com a legislação espanhola. Qualquer controvérsia relacionada à interpretação ou aplicação desta Política de Privacidade será submetida aos tribunais de Valencia (Espanha).","Contato","Se você tiver alguma pergunta ou comentário sobre esta Política de Privacidade, entre em contato conosco pelo seguinte endereço de e-mail: info@mycontacts.cloud.","Política de Cookies","Em conformidade com as disposições do artigo 22.2 da Lei de Serviços da Sociedade da Informação e do Comércio Eletrónico (LSSI), informa-se que este site utiliza cookies próprios para melhorar a experiência de navegação e oferecer conteúdo personalizado.","O que são cookies?","Um cookie ou tecnologia semelhante é um pequeno arquivo de texto armazenado no dispositivo do usuário quando ele visita um site. Os cookies permitem que o site reconheça o usuário, lembre suas preferências e forneça uma experiência personalizada.","Que tipos de cookies este site utiliza?","Este site utiliza os seguintes cookies:","Cookies necessários","Esses cookies são essenciais para o funcionamento do site. Geralmente, são configurados apenas em resposta a ações realizadas pelo usuário, como definir preferências de privacidade. O usuário pode configurar seu navegador para bloquear ou alertar sobre esses cookies, mas algumas partes do site podem não funcionar. Esses cookies não armazenam nenhuma informação de identificação pessoal.","Cookies funcionais","Esses cookies permitem que o site lembre as escolhas feitas pelo usuário (como idioma) e forneça recursos aprimorados e mais personalizados. Eles também servem para armazenar temporariamente os dados pessoais preenchidos pelo usuário no formulário de contato e no formulário de assinatura da newsletter.","Como posso gerenciar os cookies?","O usuário tem a opção de aceitar ou recusar cada tipo de cookie no link 'Configurações de cookies', que se encontra no final da página do site. O usuário também pode gerenciar os cookies por meio das configurações do seu navegador. Na maioria dos navegadores da web, é possível permitir, bloquear ou excluir os cookies instalados no dispositivo. Cada navegador possui suas próprias instruções sobre como gerenciar os cookies. Abaixo estão links para a documentação dos navegadores mais comuns:","Modificações na Política de Cookies","O responsável pelo site reserva-se o direito de modificar esta Política de Cookies a qualquer momento. É recomendável que o usuário revise periodicamente esta página para se manter informado sobre as alterações e atualizações.","Contato","Se tiver alguma pergunta ou comentário sobre esta Política de Cookies, entre em contato conosco pelo seguinte endereço de e-mail: info@mycontacts.cloud.","Eu li e aceitei a ","Obrigado por se juntar!"],"it":["Avviso Legale","Responsabile del Sito Web","In conformità a quanto stabilito dal Regolamento generale sulla protezione dei dati (GDPR) e dalla Legge organica sulla protezione dei dati personali e sulla garanzia dei diritti digitali (LOPDGDD), si informa che il responsabile del sito web mycontacts.cloud (di seguito il 'Sito Web') è:","Responsabile: ","Indirizzo: ","E-mail: ","Finalità del Sito Web","Il sito web ha lo scopo di fornire informazioni sull'applicazione web My Contacts.","Raccolta e Trattamento dei Dati Personali","Il responsabile del Sito Web adempie alle direttive del GDPR e del LOPDGDD in materia di protezione dei dati personali e garantisce l'uso corretto e il trattamento dei dati personali dell'utente. Per ulteriori informazioni su come raccogliamo, utilizziamo e proteggiamo i tuoi dati personali, consulta la nostra Informativa sulla privacy.","Proprietà Intellettuale e Industriale","Tutti i diritti di proprietà intellettuale e industriale del Sito Web e dei suoi contenuti, compresi testi, immagini, design, loghi, software, nomi commerciali, marchi, ecc., appartengono al responsabile del Sito Web o a terzi che ne hanno autorizzato l'uso. È vietata qualsiasi forma di riproduzione, distribuzione, comunicazione al pubblico, trasformazione o qualsiasi altra attività che possa essere effettuata sui contenuti del Sito Web, salvo espressa autorizzazione scritta del responsabile del Sito Web.","Limitazione di Responsabilità","Il responsabile del Sito Web non è responsabile di errori od omissioni nelle informazioni pubblicate sul Sito Web, né di eventuali danni derivanti dall'utilizzo del Sito Web. Allo stesso modo, il responsabile del Sito Web non si assume responsabilità per i contenuti dei siti web collegati dal Sito Web.","Legislazione e Giurisdizione Applicabili","Il presente Avviso Legale è disciplinato dalla legislazione spagnola in vigore. Eventuali controversie o conflitti derivanti dall'accesso o dall'utilizzo del Sito Web saranno sottoposti alla giurisdizione dei tribunali di Valencia (Spagna), con espressa rinuncia ad ogni altra giurisdizione che potrebbe competere.","Contatti","Se hai domande o commenti riguardanti il presente Avviso Legale, puoi contattarci all'indirizzo e-mail seguente: info@mycontacts.cloud.","Informativa sulla Privacy","Responsabile del Trattamento dei Dati","In conformità alle disposizioni del Regolamento generale sulla protezione dei dati (GDPR) e della Legge organica sulla protezione dei dati personali e sulla garanzia dei diritti digitali (LOPDGDD), si informa che il responsabile del trattamento dei dati personali raccolti tramite il sito web mycontacts.cloud (di seguito, il 'Sito Web') è:","Responsabile:","Indirizzo:","E-mail:","Raccolta e Trattamento dei Dati Personali","Il responsabile del trattamento dei dati personali si conforma alle direttive del GDPR e della LOPDGDD per quanto riguarda la protezione dei dati personali degli utenti e garantisce l'utilizzo corretto e il trattamento di tali dati. I dati personali raccolti tramite il Sito Web saranno trattati in modo confidenziale e non saranno utilizzati per scopi diversi da quelli specificati in questa Informativa sulla Privacy, salvo il consenso preventivo dell'utente.","Finalità del Trattamento dei Dati","I dati personali forniti dagli utenti tramite il Sito Web saranno utilizzati per le seguenti finalità:","Rispondere a domande e richieste inviate tramite il modulo di contatto, previo consenso","Inviare informazioni sull'app My Contacts, previa iscrizione alla newsletter e previo consenso","Gestire e mantenere la relazione commerciale con gli utenti","Effettuare analisi statistiche e studi di mercato","Sicurezza dei Dati Personali","Il responsabile del trattamento dei dati personali ha adottato le misure tecniche e organizzative necessarie per garantire la sicurezza dei dati personali e prevenire alterazioni, perdite, accessi non autorizzati o trattamenti non consentiti, tenendo conto dello stato della tecnologia, della natura dei dati memorizzati e dei rischi a cui sono esposti. Tuttavia, il responsabile del trattamento non può garantire la sicurezza assoluta dei dati trasmessi attraverso Internet.","Diritti dell'Utente","L'utente ha il diritto di:","Accedere ai propri dati personali e richiedere informazioni sul loro trattamento","Correggere dati personali inesatti o incompleti","Cancellare i propri dati personali quando non sono più necessari per le finalità per cui sono stati raccolti","Limitare il trattamento dei propri dati personali in determinate circostanze","Trasferire i propri dati personali a un altro responsabile del trattamento in un formato strutturato, comunemente usato e leggibile da macchina","Opporsi al trattamento dei propri dati personali in determinate circostanze e per motivi legati alla propria situazione particolare","Tali diritti possono essere esercitati attraverso i dati di contatto forniti in questa Informativa sulla Privacy.","Link a Siti Web di Terze Parti","Il Sito Web può contenere link a siti web di terze parti. Il responsabile del trattamento dei dati non è responsabile delle pratiche sulla privacy o dei contenuti di tali siti web. Si consiglia agli utenti di leggere le politiche sulla privacy dei siti web di terze parti prima di fornire qualsiasi informazione personale.","Modifiche all'Informativa sulla Privacy","Il responsabile del trattamento si riserva il diritto di modificare questa Informativa sulla Privacy in qualsiasi momento. Si consiglia agli utenti di consultare periodicamente questa pagina per essere informati sugli aggiornamenti.","Giurisdizione e Legge Applicabile","Questa Informativa sulla Privacy è disciplinata e interpretata in conformità alla legislazione spagnola. Eventuali controversie derivanti dall'interpretazione o dall'applicazione di questa Informativa sulla Privacy saranno sottoposte ai tribunali di Valencia (Spagna).","Contatti","Se hai domande o commenti su questa Informativa sulla Privacy, puoi contattarci all'indirizzo e-mail seguente: info@mycontacts.cloud.","Informativa sui cookie","In conformità con quanto stabilito dall'articolo 22.2 della Legge sui servizi della società dell'informazione e del commercio elettronico (LSSI), si informa che questo sito web utilizza cookie propri per migliorare l'esperienza di navigazione e offrire contenuti personalizzati.","Cosa sono i cookie?","Un cookie o una tecnologia simile è un piccolo file di testo che viene memorizzato sul dispositivo dell'utente quando visita un sito web. I cookie consentono al sito web di riconoscere l'utente, ricordare le sue preferenze e fornire un'esperienza personalizzata.","Quali tipi di cookie utilizza questo sito web?","Questo sito web utilizza i seguenti cookie:","Cookie necessari","Questi cookie sono essenziali per il funzionamento del sito web. Di solito vengono impostati solo in risposta ad azioni compiute dall'utente, come impostare le preferenze sulla privacy. L'utente può configurare il proprio browser per bloccare o essere avvertito della presenza di questi cookie, ma alcune parti del sito potrebbero non funzionare correttamente. Questi cookie non memorizzano informazioni personali identificabili.","Cookie funzionali","Questi cookie permettono al sito web di ricordare le scelte effettuate dall'utente (come la lingua) e fornire funzionalità migliorate e personalizzate. Servono anche a memorizzare temporaneamente i dati personali dell'utente inseriti nel modulo di contatto e nel modulo di iscrizione alla newsletter.","Come posso gestire i cookie?","L'utente ha la possibilità di accettare o rifiutare ciascun tipo di cookie tramite il collegamento 'Impostazioni cookie', che si trova in fondo alla pagina web. L'utente può anche gestire i cookie attraverso le impostazioni del proprio browser. Nella maggior parte dei browser web è possibile consentire, bloccare o eliminare i cookie installati sul dispositivo. Ogni browser ha le proprie istruzioni su come gestire i cookie. Di seguito sono riportati i collegamenti alla documentazione dei browser più comuni:","Modifiche alla politica dei cookie","Il responsabile del sito web si riserva il diritto di modificare questa politica dei cookie in qualsiasi momento. Si consiglia all'utente di rivedere periodicamente questa pagina per essere informato sulle modifiche e gli aggiornamenti.","Contatto","Se hai domande o commenti su questa politica dei cookie, puoi contattarci all'indirizzo e-mail seguente: info@mycontacts.cloud.","Ho letto e accettato la ","Grazie per esserti unito/a!"],"de":["Impressum","Verantwortlicher für die Website","Gemäß den Bestimmungen der Datenschutz-Grundverordnung (DSGVO) und des Organischen Gesetzes zum Schutz personenbezogener Daten und zur Gewährleistung der digitalen Rechte (LOPDGDD) wird darauf hingewiesen, dass der verantwortliche Anbieter für die Website mycontacts.cloud (im Folgenden 'Website') ist:","Verantwortlicher: ","Adresse: ","E-Mail: ","Zweck der Website","Die Website hat zum Ziel, Informationen über die Webanwendung My Contacts bereitzustellen.","Erhebung und Verarbeitung personenbezogener Daten","Der verantwortliche Anbieter für die Website hält sich an die Richtlinien der DSGVO und der LOPDGDD in Bezug auf den Schutz personenbezogener Daten und gewährleistet die korrekte Verwendung und Verarbeitung der personenbezogenen Daten des Benutzers. Weitere Informationen dazu, wie wir personenbezogene Daten erfassen, verwenden und schützen, finden Sie in unserer Datenschutzrichtlinie.","Geistiges und gewerbliches Eigentum","Alle geistigen und gewerblichen Eigentumsrechte an der Website und ihren Inhalten, einschließlich Texten, Bildern, Designs, Logos, Software, Handelsnamen, Marken usw., gehören dem verantwortlichen Anbieter der Website oder Dritten, die ihre Nutzung autorisiert haben. Jegliche Form der Vervielfältigung, Verbreitung, öffentlichen Kommunikation, Transformation oder sonstige Nutzung der Inhalte der Website ist ohne ausdrückliche schriftliche Genehmigung des verantwortlichen Anbieters der Website untersagt.","Haftungsbeschränkung","Der verantwortliche Anbieter der Website haftet nicht für Fehler oder Auslassungen in den auf der Website veröffentlichten Informationen und übernimmt keine Haftung für mögliche Schäden, die sich aus der Nutzung der Website ergeben können. Ebenso übernimmt der verantwortliche Anbieter der Website keine Verantwortung für die Inhalte von Websites, die von der Website verlinkt sind.","Anwendbares Recht und Gerichtsstand","Diese rechtlichen Hinweise unterliegen der geltenden spanischen Gesetzgebung. Etwaige Streitigkeiten oder Konflikte, die sich aus dem Zugriff oder der Nutzung der Website ergeben können, unterliegen der Gerichtsbarkeit der Gerichte von Valencia (Spanien). Dabei wird ausdrücklich auf jede andere Zuständigkeit verzichtet, die möglicherweise zustehen könnte.","Kontakt","Bei Fragen oder Kommentaren zu diesem Impressum können Sie uns unter folgender E-Mail-Adresse kontaktieren: info@mycontacts.cloud.","Datenschutzrichtlinie","Verantwortlicher für die Datenverarbeitung","Gemäß den Bestimmungen der Datenschutz-Grundverordnung (DSGVO) und des Organischen Gesetzes zum Schutz personenbezogener Daten und zur Gewährleistung der digitalen Rechte (LOPDGDD) wird darauf hingewiesen, dass der Verantwortliche für die Verarbeitung der über die Website mycontacts.cloud erhobenen personenbezogenen Daten (im Folgenden 'Website') ist:","Verantwortlicher:","Adresse:","E-Mail:","Erhebung und Verarbeitung personenbezogener Daten","Der Verantwortliche für die Verarbeitung personenbezogener Daten erfüllt die Richtlinien der DSGVO und der LOPDGDD in Bezug auf den Schutz der personenbezogenen Daten der Nutzer und gewährleistet die ordnungsgemäße Nutzung und Verarbeitung dieser Daten. Die über die Website erhobenen personenbezogenen Daten werden vertraulich behandelt und nicht für andere Zwecke verwendet als die in dieser Datenschutzrichtlinie angegebenen, sofern der Nutzer seine vorherige Zustimmung gegeben hat.","Zweck der Datenverarbeitung","Die vom Nutzer über die Website bereitgestellten personenbezogenen Daten werden für folgende Zwecke verwendet:","Beantwortung von Anfragen und Anfragen über das Kontaktformular, sofern die entsprechende Zustimmung erteilt wurde","Versenden von Informationen über die App My Contacts, sofern der Nutzer den Newsletter abonniert hat und die entsprechende Zustimmung erteilt hat","Verwaltung und Aufrechterhaltung der Geschäftsbeziehung zu den Nutzern","Durchführung von statistischen Analysen und Marktforschung","Sicherheit personenbezogener Daten","Der Verantwortliche für die Verarbeitung personenbezogener Daten hat die erforderlichen technischen und organisatorischen Maßnahmen ergriffen, um die Sicherheit personenbezogener Daten zu gewährleisten und deren Veränderung, Verlust, unbefugten Zugriff oder unbefugte Verarbeitung zu verhindern, unter Berücksichtigung des Standes der Technik, der Art der gespeicherten Daten und der damit verbundenen Risiken. Der Verantwortliche für die Verarbeitung kann jedoch keine absolute Sicherheit der über das Internet übertragenen Daten garantieren.","Rechte des Nutzers","Der Nutzer hat das Recht:","Zugriff auf seine personenbezogenen Daten zu erhalten und Informationen über deren Verarbeitung anzufordern","Unrichtige oder unvollständige personenbezogene Daten zu berichtigen","Löschen seiner personenbezogenen Daten, wenn sie für die Zwecke, für die sie erhoben wurden, nicht mehr erforderlich sind","Die Verarbeitung seiner personenbezogenen Daten in bestimmten Fällen einzuschränken","Seine personenbezogenen Daten in einem strukturierten, gängigen und maschinenlesbaren Format an einen anderen Verantwortlichen zu übertragen","Sich in bestimmten Fällen und aus Gründen, die mit seiner besonderen Situation zusammenhängen, der Verarbeitung seiner personenbezogenen Daten zu widersetzen","Diese Rechte können über die in dieser Datenschutzrichtlinie angegebenen Kontaktdaten ausgeübt werden.","Links zu Websites von Dritten","Die Website kann Links zu Websites von Dritten enthalten. Der Verantwortliche für die Datenverarbeitung ist nicht für die Datenschutzpraktiken oder den Inhalt dieser Websites verantwortlich. Den Nutzern wird empfohlen, die Datenschutzrichtlinien von Websites von Dritten zu lesen, bevor sie personenbezogene Informationen bereitstellen.","Änderungen der Datenschutzrichtlinie","Der Verantwortliche für die Datenverarbeitung behält sich das Recht vor, diese Datenschutzrichtlinie jederzeit zu ändern. Den Nutzern wird empfohlen, diese Seite regelmäßig auf Aktualisierungen zu überprüfen.","Gerichtsstand und anwendbares Recht","Diese Datenschutzrichtlinie unterliegt spanischem Recht und wird entsprechend ausgelegt. Etwaige Streitigkeiten im Zusammenhang mit der Auslegung oder Anwendung dieser Datenschutzrichtlinie unterliegen der Zuständigkeit der Gerichte von Valencia (Spanien).","Kontakt","Wenn Sie Fragen oder Kommentare zu dieser Datenschutzrichtlinie haben, können Sie uns über die folgende E-Mail-Adresse kontaktieren: info@mycontacts.cloud.","Cookie-Richtlinie","Gemäß den Bestimmungen des Artikels 22.2 des Gesetzes über die Dienste der Informationsgesellschaft und des elektronischen Geschäftsverkehrs (LSSI) wird darauf hingewiesen, dass diese Website eigene Cookies zur Verbesserung des Browsing-Erlebnisses und zur Bereitstellung personalisierter Inhalte verwendet.","Was sind Cookies?","Ein Cookie oder eine ähnliche Technologie ist eine kleine Textdatei, die auf dem Gerät des Benutzers gespeichert wird, wenn er eine Website besucht. Cookies ermöglichen es der Website, den Benutzer zu erkennen, seine Präferenzen zu speichern und ein personalisiertes Erlebnis zu bieten.","Welche Arten von Cookies werden auf dieser Website verwendet?","Diese Website verwendet die folgenden Cookies:","Notwendige Cookies","Diese Cookies sind für die Funktionalität der Website unbedingt erforderlich. Sie werden in der Regel nur als Reaktion auf vom Benutzer durchgeführte Aktionen festgelegt, wie z. B. die Festlegung von Datenschutzeinstellungen. Der Benutzer kann seinen Browser so konfigurieren, dass diese Cookies blockiert oder über sie informiert wird, aber einige Teile der Website funktionieren möglicherweise nicht. Diese Cookies speichern keine persönlich identifizierbaren Informationen.","Funktionale Cookies","Diese Cookies ermöglichen es der Website, die vom Benutzer getroffenen Auswahlmöglichkeiten (wie z. B. Sprache) zu speichern und erweiterte und persönlichere Funktionen bereitzustellen. Sie dienen auch dazu, vorübergehend die vom Benutzer im Kontaktformular und im Newsletter-Anmeldeformular eingegebenen persönlichen Daten zu speichern.","Wie kann ich Cookies verwalten?","Der Benutzer hat die Möglichkeit, jeden Typ von Cookie über den Link 'Cookie-Einstellungen', der am Ende der Webseite zu finden ist, anzunehmen oder abzulehnen. Der Benutzer kann Cookies auch über die Einstellungen seines Browsers verwalten. In den meisten Webbrowsern ist es möglich, Cookies auf dem Gerät zu erlauben, zu blockieren oder zu löschen. Jeder Browser hat seine eigenen An leitungen zur Verwaltung von Cookies. Nachfolgend finden Sie Links zur Dokumentation der gängigsten Browser:","Änderungen der Cookie-Richtlinie","Der Website-Betreiber behält sich das Recht vor, diese Cookie-Richtlinie jederzeit zu ändern. Es wird empfohlen, dass der Benutzer diese Seite regelmäßig überprüft, um über Änderungen und Aktualisierungen informiert zu bleiben.","Kontakt","Bei Fragen oder Kommentaren zu dieser Cookie-Richtlinie können Sie uns unter folgender E-Mail-Adresse kontaktieren: info@mycontacts.cloud.","Ich habe gelesen und akzeptiert die ","Vielen Dank fürs Mitmachen!"],"ca":["Avís Legal","Responsable del Lloc Web","D'acord amb el que disposa el Reglament General de Protecció de Dades (RGPD) i la Llei Orgànica de Protecció de Dades Personals i Garantia dels Drets Digitals (LOPDGDD), es comunica que el responsable del lloc web mycontacts.cloud (d'ara endavant, el 'Lloc Web') és:","Responsable: ","Domicili: ","Correu electrònic: ","Finalitat del Lloc Web","La finalitat del Lloc Web és proporcionar informació sobre l'aplicació web My Contacts.","Recollida i Tractament de Dades Personals","El responsable del Lloc Web compleix les directrius del RGPD i la LOPDGDD en relació amb la protecció de les dades personals i garanteix el correcte ús i tractament de les dades personals de l'usuari. Per obtenir més informació sobre com recopilem, utilitzem i protegim les teves dades personals, consulta la nostra Política de Privadesa.","Propietat Intel·lectual i Industrial","Tots els drets de propietat intel·lectual i industrial del Lloc Web i els seus continguts, incloent-hi textos, imatges, dissenys, logotips, programari, noms comercials, marques, etc., pertanyen al responsable del Lloc Web o a tercers que han autoritzat el seu ús. Queda prohibida qualsevol forma de reproducció, distribució, comunicació pública, transformació o qualsevol altra activitat que es pugui realitzar amb els continguts del Lloc Web, llevat que s'obtingui l'autorització expressa per escrit del responsable del Lloc Web.","Limitació de Responsabilitat","El responsable del Lloc Web no es fa responsable dels errors o omissions en la informació publicada al Lloc Web, ni dels possibles danys derivats de l'ús del Lloc Web. A més, el responsable del Lloc Web no es fa responsable dels continguts dels llocs web enllaçats des del Lloc Web.","Llei i Jurisdicció Aplicables","Aquest Avís Legal es regeix per la legislació espanyola vigent. Qualsevol controvèrsia o conflicte que pugui sorgir de l'accés o l'ús del Lloc Web es sotmetrà a la jurisdicció dels tribunals de València (Espanya), renunciant expressament a qualsevol altre for que pugui correspondre.","Contacte","Si tens alguna pregunta o comentari sobre aquest Avís Legal, pots posar-te en contacte amb nosaltres a través de la següent adreça de correu electrònic: info@mycontacts.cloud.","Política de Privadesa","Responsable del Tractament de Dades","D'acord amb el que disposa el Reglament General de Protecció de Dades (RGPD) i la Llei Orgànica de Protecció de Dades Personals i Garantia dels Drets Digitals (LOPDGDD), es comunica que el responsable del tractament de les dades personals recollides a través del lloc web mycontacts.cloud (d'ara endavant, el 'Lloc Web') és:","Responsable: ","Domicili: ","Correu electrònic: ","Recollida i Tractament de Dades Personals","El responsable del tractament de les dades personals compleix les directrius del RGPD i la LOPDGDD en relació amb la protecció de les dades personals dels usuaris i garanteix el correcte ús i tractament de les mateixes. Les dades personals recollides a través del Lloc Web seran tractades de forma confidencial i no es faran servir per a fins diferents dels especificats en aquesta Política de Privadesa, llevat que s'obtingui el consentiment previ de l'usuari.","Finalitat del Tractament de Dades","Les dades personals proporcionades pels usuaris a través del Lloc Web seran utilitzades amb la finalitat de:","Respondre a consultes i sol·licituds realitzades a través del formulari de contacte i hagi concedit el consentiment corresponent","Enviar informació sobre l'aplicació My Contacts sempre que s'hagi subscrit a la newsletter i hagi atorgat el consentiment corresponent","Gestionar i mantenir la relació comercial amb els usuaris","Realitzar anàlisis estadístics i estudis de mercat","Seguretat de les Dades Personals","El responsable del tractament de les dades personals ha adoptat les mesures tècniques i organitzatives necessàries per garantir la seguretat de les dades personals i evitar-ne l'alteració, pèrdua, tractament o accés no autoritzat, tenint en compte l'estat de la tecnologia, la natura de les dades emmagatzemades i els riscos als quals estan exposades. No obstant això, el responsable del tractament no pot garantir la seguretat absoluta de les dades transmeses a través d'Internet.","Drets de l'Usuari","L'usuari té dret a:","Accedir a les seves dades personals i sol·licitar informació sobre com s'estan tractant","Rectificar les dades personals inexactes o incompletes","Suprimir les dades personals quan ja no siguin necessàries per als fins per als quals es van recollir","Limitar el tractament de les dades personals en determinades circumstàncies","Portar les dades personals a un altre responsable del tractament en un format estructurat i d'ús comú","Oposar-se al tractament de les dades personals en determinades circumstàncies i per motius relacionats amb la seva situació particular","L'exercici d'aquests drets es pot dur a terme a través de les dades de contacte proporcionades en aquesta Política de Privadesa.","Enllaços a Llocs Web de Tercers","El Lloc Web pot contenir enllaços a llocs web de tercers. El responsable del tractament no es fa responsable de les pràctiques de privadesa ni del contingut d'aquests llocs web. Es recomana als usuaris llegir les polítiques de privadesa dels llocs web de tercers abans de proporcionar qualsevol informació personal.","Modificacions de la Política de Privadesa","El responsable del tractament es reserva el dret de modificar aquesta Política de Privadesa en qualsevol moment. Es recomana als usuaris revisar periòdicament aquesta pàgina per estar informats de les actualitzacions.","Jurisdicció i Llei Aplicables","Aquesta Política de Privadesa es regeix i interpreta d'acord amb la legislació espanyola. Qualsevol controvèrsia que pugui sorgir en relació amb la interpretació o aplicació d'aquesta Política de Privadesa serà sotmesa als tribunals de València (Espanya).","Contacte","Si tens alguna pregunta o comentari sobre aquesta Política de Privadesa, pots posar-te en contacte amb nosaltres a través de la següent adreça de correu electrònic: info@mycontacts.cloud.","Política de Cookies","D'acord amb el que disposa l'article 22.2 de la Llei de Serveis de la Societat de la Informació i de Comerç Electrònic (LSSI), es comunica que aquest lloc web utilitza cookies pròpies per millorar l'experiència de navegació i oferir contingut personalitzat.","Què són les cookies?","Una cookie o tecnologia similar és un petit fitxer de text que s'emmagatzema al dispositiu de l'usuari quan visita un lloc web. Les cookies permeten que el lloc web reconegui a l'usuari, recordi les seves preferències i proporcioni una experiència personalitzada.","Quins tipus de cookies utilitza aquest lloc web?","Aquest lloc web utilitza les següents cookies:","Cookies necessàries","Aquestes cookies són essencials per al funcionament del lloc web. Generalment, es configuren només en resposta a accions realitzades per l'usuari, com ara establir preferències de privadesa. L'usuari pot configurar el seu navegador per bloquejar o alertar sobre aquestes cookies, però algunes parts del lloc no funcionaran. Aquestes cookies no emmagatzemen cap informació d'identificació personal.","Cookies funcionals","Aquestes cookies permeten que el lloc web recordi les opcions que l'usuari fa (com ara el seu idioma) i proporciona característiques millorades i més personalitzades. També serveixen per emmagatzemar temporalment les dades personals omplertes en el formulari de contacte i el formulari de subscripció a la newsletter.","Com puc gestionar les cookies?","L'usuari té l'opció d'acceptar o rebutjar cada tipus de cookies des de l'enllaç de 'Configuració de cookies', que trobarà al final de la pàgina web. L'usuari també pot gestionar les cookies a través de la configuració del seu navegador. En la majoria dels navegadors web, és possible permetre, bloquejar o eliminar les cookies instal·lades al dispositiu. Cada navegador té les seves pròpies instruccions sobre com gestionar les cookies. A continuació, es proporcionen enllaços a la documentació dels navegadors més comuns:","Modificacions de la Política de Cookies","El responsable del lloc web es reserva el dret de modificar aquesta Política de Cookies en qualsevol moment. Es recomana a l'usuari revisar periòdicament aquesta pàgina per estar informat dels canvis i actualitzacions.","Contacte","Si tens alguna pregunta o comentari sobre aquesta Política de Cookies, pots posar-te en contacte amb nosaltres a través de la següent adreça de correu electrònic: info@mycontacts.cloud.","He llegit i accepto la ","¡Gràcies per unir-te!"],"gl":["Aviso Legal","Responsable do Sitio Web","De acordo co establecido no Regulamento Xeral de Protección de Datos (RGPD) e na Lei Orgánica de Protección de Datos Persoais e Garantía dos Dereitos Dixitais (LOPDGDD), informase que o responsable do sitio web mycontacts.cloud (de agora en diante, o 'Sitio Web') é:","Responsable: ","Domicilio: ","Correo electrónico: ","Finalidade do Sitio Web","O Sitio Web ten como finalidade proporcionar información sobre a aplicación web My Contacts.","Recollida e Tratamento de Datos Persoais","O responsable do Sitio Web cumpre coas directrices do RGPD e da LOPDGDD no que se refire á protección dos datos persoais e garante o correcto uso e tratamento dos datos persoais do usuario. Para máis información sobre como recopilamos, utilizamos e protexemos os teus datos persoais, consulta a nosa Política de Privacidade.","Propiedade Intelectual e Industrial","Todos os dereitos de propiedade intelectual e industrial do Sitio Web e os seus contidos, incluíndo textos, imaxes, deseños, logotipos, software, nomes comerciais, marcas, etc., pertencen ao responsable do Sitio Web ou a terceiros que autorizaron o seu uso. Queda prohibida calquera forma de reprodución, distribución, comunicación pública, transformación ou calquera outra actividade que se poida realizar cos contidos do Sitio Web, salvo autorización expresa por escrito do responsable do Sitio Web.","Limitación de Responsabilidade","O responsable do Sitio Web non se fai responsable dos erros ou omisións na información publicada no Sitio Web, nin dos posibles danos derivados do uso do Sitio Web. Do mesmo xeito, o responsable do Sitio Web non se fai responsable dos contidos dos sitios web enlazados desde o Sitio Web.","Leis e Xurisdición Aplicables","Este Aviso Legal rexeitase pola lexislación española vixente. Calquera controversia ou conflito que poida xurdir do acceso ou uso do Sitio Web someterase á xurisdición dos tribunais de Valencia (España), renunciando expresamente a calquera outro foro que puidera corresponder.","Contacto","Se tes algunha pregunta ou comentario sobre este Aviso Legal, podes poñerte en contacto connosco a través da seguinte dirección de correo electrónico: info@mycontacts.cloud.","Política de Privacidade","Responsable do Tratamento de Datos","De acordo co establecido no Regulamento Xeral de Protección de Datos (RGPD) e na Lei Orgánica de Protección de Datos Persoais e Garantía dos Dereitos Dixitais (LOPDGDD), informase que o responsable do tratamento dos datos persoais recollidos a través do sitio web mycontacts.cloud (de agora en diante, o 'Sitio Web') é:","Responsable: ","Domicilio: ","Correo electrónico: ","Recollida e Tratamento de Datos Persoais","O responsable do tratamento dos datos persoais cumpre coas directrices do RGPD e da LOPDGDD no que se refire á protección dos datos persoais dos usuarios e garante o correcto uso e tratamento dos mesmos. Os datos persoais recollidos a través do Sitio Web serán tratados de forma confidencial e non se utilizarán para fins diferentes aos especificados nesta Política de Privacidade, salvo que se obtenga o consentimento previo do usuario.","Finalidade do Tratamento de Datos","Os datos persoais proporcionados polos usuarios a través do Sitio Web serán utilizados coa finalidade de:","Respostas a consultas e solicitudes realizadas a través do formulario de contacto e que teña concedido o consentimento correspondente","Envío de información sobre a app My Contacts sempre que teña subscribido á newsletter e teña outorgado o consentimento correspondente","Xestión e mantemento da relación comercial cos usuarios","Realización de análises estatísticos e estudos de mercado","Seguridade dos Datos Persoais","O responsable do tratamento dos datos persoais adoptou as medidas técnicas e organizativas necesarias para garantir a seguridade dos datos persoais e evitar a súa alteración, perda, tratamento ou acceso non autorizado, tendo en conta o estado da tecnoloxía, a natureza dos datos almacenados e os riscos aos que están expostos. Sen embargo, o responsable do tratamento non pode garantir a seguridade absoluta dos datos transmitidos a través de Internet.","Dereitos do Usuario","O usuario ten dereito a:","Acceder aos seus datos persoais e solicitar información sobre como se están tratando","Rectificar os datos persoais inexactos ou incompletos","Suprimir os datos persoais cando xa non sexan necesarios para os fins para os que foron recollidos","Limitar o tratamento dos datos persoais en determinadas circunstancias","Portar os datos persoais a outro responsable do tratamento nun formato estruturado e de uso común","Opoñerse ao tratamento dos datos persoais en determinadas circunstancias e por motivos relacionados coa súa situación particular","O exercicio destes dereitos poderá levarse a cabo a través dos datos de contacto proporcionados nesta Política de Privacidade.","Enlaces a Sitios Web de Terceiros","O Sitio Web pode conter enlaces a sitios web de terceiros. O responsable do tratamento non se fai responsable das prácticas de privacidade nin do contido de ditos sitios web. Recoméndase aos usuarios ler as políticas de privacidade dos sitios web de terceiros antes de proporcionar calquera información persoal.","Modificacións da Política de Privacidade","O responsable do tratamento resérvase o dereito de modificar esta Política de Privacidade en calquera momento. Recoméndase aos usuarios revisar periodicamente esta páxina para estar informados das actualizacións.","Xurisdición e Lexislatión Aplicables","Esta Política de Privacidade rexeitase e interpretarase de acordo coa lexislación española. Calquera controvérsia que poida xurdir en relación coa interpretación ou aplicación desta Política de Privacidade someterase aos tribunais de Valencia (España).","Contacto","Se tes algunha pregunta ou comentario sobre esta Política de Privacidade, podes poñerte en contacto connosco a través da seguinte dirección de correo electrónico: info@mycontacts.cloud.","Política de Cookies","De acordo co establecido no artigo 22.2 da Lei de Servizos da Sociedade da Información e de Comercio Electrónico (LSSI), informase que este sitio web utiliza cookies propias para mellorar a experiencia de navegación e ofrecer contido personalizado.","Que son as cookies?","Unha cookie ou tecnoloxía similar é un pequeno ficheiro de texto que se almacena no dispositivo do usuario cando visita un sitio web. As cookies permiten que o sitio web recoñeza ao usuario, lembre as súas preferencias e proporcione unha experiencia personalizada.","Que tipos de cookies utiliza este sitio web?","Este sitio web utiliza as seguintes cookies:","Cookies necesarias","Estas cookies son esenciais para o funcionamento do sitio web. Xeralmente, establécense só en resposta a accións realizadas polo usuario, como establecer preferencias de privacidade. O usuario pode configurar o seu navegador para bloquear ou alertar sobre estas cookies, pero algunhas partes do sitio non funcionarán. Estas cookies non almacenarán ningunha información de identificación persoal.","Cookies funcionais","Estas cookies permiten que o sitio web lembre as escolles que o usuario fai (como o seu idioma) e proporciona características melloradas e máis personalizadas. Tamén serven para almacenar temporalmente os datos persoais encheridos no formulario de contacto e no formulario de subscripción á newsletter.","Como podo xestionar as cookies?","O usuario ten a opción de aceptar ou rexeitar cada tipo de cookies desde o enlace de 'Configuración de cookies', que atopará ao final da páxina web. O usuario tamén pode xestionar as cookies a través da configuración do seu navegador. Na maioría dos navegadores web, é posible permitir, bloquear ou eliminar as cookies instaladas no dispositivo. Cada navegador ten as súas propias instrucións sobre como xestionar as cookies. A continuación, propóñense enlaces á documentación dos navegadores máis comúns:","Modificacións da Política de Cookies","O responsable do sitio web resérvase o dereito de modificar esta Política de Cookies en calquera momento. Recoméndase ao usuario revisar periodicamente esta páxina para estar informado dos cambios e actualizacións.","Contacto","Se tes algunha pregunta ou comentario sobre esta Política de Cookies, podes poñerte en contacto connosco a través da seguinte dirección de correo electrónico: info@mycontacts.cloud.","Lin e aceptei a ","¡Grazas por unirte!"],"eu":["Legal Oharra","Webgunearen Jabea","Datu Pertsonalak eta Digitalen Eskubideen Babesa (RGPD) eta Datu Pertsonalak Babesteko eta Eskubide Digitalen Bidezko Lege Orgánikoa (LOPDGDD) ezarritakoaren arabera, webgunearen mycontacts.cloud (hemenjokoan, 'Webgunea') jabea da:","Jabea: ","Helbidea: ","Posta-elektronikoa: ","Webgunearen Helburua","Webgunearen helburua My Contacts web aplikazioari buruzko informazioa eskaintzea da.","Datu Pertsonalak Bildu eta Tratatu","Webgunearen Jabeak RGPD eta LOPDGDDren aginduei jarraiki datu pertsonalen babesa bermatzen du eta erabiltzailearen datu pertsonalen erabilera eta tratamendu egokia bermatzen du. Zure datu pertsonalak nola biltzen, erabilten eta babesten ditugun gehiago jakin nahi baduzu, gure Pribatutasun Politika ikusi.","Hirugarrenen Propietate Intelektuala eta Industria","Webgunearen eta bere edukiaren propietate intelektual eta industria eskubide guztiak, testuak, irudiak, diseinuak, logotipoak, softwareak, enpresa izenak, markak, etab., Webgunearen jabearen edo beren erabilera baimentzen duten hirugarrenen esku daude. Webgunearen edukien eraldaketa, banaketa, komunikazio publikoa, eraldaketa edo beste edozein jarduera debekatuta dago, webgunearen jabearen idazki baimen bereziarekin salbu.","Erantzukizuna Murriztua","Webgunearen jabeak ez du webgunean argitaratutako informazioaren erroreak edo ezustekoak ezabaltzeaz edo webgunearen erabilera eratzen dituen ondorio kaltegarrien erantzule izango. Era berean, webgunearen jabeak webgunearekin lotutako webguneen edukiei erantzule ez da.","Eskumen eta Jurisdikzioa","Oharra Hau Espainiako legeriak murrizten du. Webgunearen erabilera edo erabilera denean sortu daitekeen eztabaida edo gatazkak Valentiako (Espainia) auzitegietara aurkeztuko dira, nahi izanez gero, esleipen bat kendu nahi duten beste auzitegiak alde batera utzita.","Kontaktua","Ohar hau edo erantzun bat izanez gero, jar zaitez gurekin posta-elektroniko honen bidez: info@mycontacts.cloud.","Pribatutasun Politika","Datu Tratamenduaren Erantzulea","Webgunearen datu pertsonalak biltzen dituenaren erantzulea webgunearen mycontacts.cloud bidez (hemenjokoan, 'Webgunea') da:","Erantzulea: ","Helbidea: ","Posta-elektronikoa: ","Datu Pertsonalen Bildu eta Tratamenduaren Helburua","Datu pertsonalak biltzen dituenaren erantzuleak datu pertsonalen babesa burutzeko eta erabili ahal izateko RGPD eta LOPDGDDren aginduei jarraiki datu pertsonalen baliabideak eta tratamendu egokia bermatzen ditu. Webgunearen bidez bildutako datu pertsonalak konfidentzialki tratatuko dira eta hauetako edozein helburu ez dute izango, erabiltzaileak aurrez aurre emandako baimena izan ezik.","Datu Tratamenduaren Helburua","Erabiltzaileek Webgunearen bidez emandako datu pertsonalak hurrengo helburuetarako erabiliko dira:","Kontsulta eta eskariak erantzuteko, kontaktu formularioaren bidez egina eta baimen egokia eman duenak","My Contacts aplikazioari buruzko informazioa bidaltzea beti ere newsletterari harpidetu eta baimen egokia eman duenak","Erabiltzaileekin harreman komertziala kudeatu eta mantentzea","Estadistikak eta merkatu ikuspegiak egin","Datu Pertsonalen Segurtasuna","Datu pertsonalak tratatzen dituenaren erantzuleak datu pertsonalen segurtasuna bermatzeko beharrezko neurri tekniko eta antolakuntzak hartu ditu, datuak aldatu, galdu, tratatu edo sarrera baimenik gabea izatea ekiditeko. Teknologiaren egoera, gordeta dauden datuen natura eta aurreikuspenak kontuan harturik. Hala ere, datu pertsonalen segurtasun absolutua ezin da bermatu Internet bidez transmititzen diren datuei dagokienez.","Erabiltzaileen Eskubideak","Erabiltzaileak eskubidea dauka:","Haren datu pertsonalak atzitzea eta nola tratatzen ari diren jakitea","Datuen pertsonalak zuzendu, baliogabekoak edo osatuak badira","Zuzenbidea datu pertsonalak ez direnean erabili behar direnean","Datu pertsonalen tratamendua murriztu, betiere une jakin batean","Datuen pertsonalak beste datu pertsonalak tratatzeko moldabide estrukturetan eta erabilizkoan eramatea","Datuen pertsonalen tratamenduari aurka egitea, betiere haien egoera bereziarekin lotuta dagoen arren","Eskubide hauek gauzatu ahal izango dira Pribatutasun Politika honetan emandako kontaktu datuei begiratuz.","Hirugarrenen Webguneetarako Estekak","Webguneak hirugarrenen webguneetara estekak izan ditzake. Datuak datu pertsonalak nola babesteko eta webgune horien edukia ez dago bermatuta datu pertsonalen babesa burutzeko ezarritako praktiken arabera. Erabiltzaileei aholkatzen zaie hirugarrenen webguneen pribatutasun politikak irakurri datu pertsonalak ematea baino lehen.","Pribatutasun Politikaren Aldaketak","Datuen tratamenduaren erantzuleak berak du Política de Privacidad honetan aldaketak egin ditzakeela eskubidea. Erabiltzaileei gomendatzen zaie orri hau periodikoki ikustea eguneratutako informazioa izateko.","Jurisdikzioa eta Lege Aplikagarria","Pribatutasun Politika hau Espainiako legeriak araberakoa da eta interpretatuko da. Pribatutasun Politika honi buruzko interpretazio edo aplikazioarekin lotutako eztabaida bat sortu daitekeen edo sortu daitekeen edozein kontrobersia Valentiako (Espainia) auzitegei aurkeztuko zaie.","Kontaktua","Pribatutasun Politika hau buruz duzun galdera edo iruzkina baduzu, gurekin harremanetan jarri ahal zara honako posta elektroniko helbide honekin: info@mycontacts.cloud.","Cookie-en Politika","Informazioaren Gizartearen eta Merkataritza Elektronikoko Zerbitzuen Legearen (LSSI) 22.2 artikuluan ezarritakoaren arabera, webgune honek bere cookieak hobetzeko eta eduki pertsonalizatuak eskaintzeko erabiltzen ditu cookie propietarioak. ","Zer dira cookie-ak?","Cookie edo teknologia antzeko baliabide txikia da, erabiltzaileak webgune bat bisitatzen duenean bere gailuan gordetzen dena. Cookie-ek webguneak erabiltzailea ezagutzea, bere gogokoenak gogoratzea eta esperientzia pertsonalizatua eskaintzea ahalbidetzen dute.","Zein motako cookie erabiltzen ditu webgune honek?","Webgune honek hurrengo cookie erabiliko ditu:","Beharrezkoak diren cookie-ak","Cookie hauek webgunearen funtzionamendua beharrezkoa da. Oro har, erabiltzaileak egiten dituen ekintza erantzuten dieten erantzuten dute, pribatutasun gogokoenak ezarri. Erabiltzaileak bere nabigatzailea konfiguratu dezake cookie hauek blokeatzeko edo alarma-egoerara ekartzea, baina webgunearen zati batzuk ez dute funtzionatuko. Cookie hauek ez dute inolako datu identifikatzailea gorde.","Cookie funtzionalak","Cookie hauek webguneak erabiltzen dituen hautapenak gogoratzen dituzte (adibidez, hizkuntza). Ondorengo ezaugarriak eta pertsonalizatutako ezaugarriak eskaintzen dituzte. Era berean, kontaktu formularioan eta newslettera harpidetzearen formularioan bete dituzun datu pertsonalak bertan gordeko dira.","Nola kudeatu cookie-ak?","Erabiltzaileak aukera dauka cookie mota bakoitzari baimena emateko edo ukituak emateko webgunearen azpian aurkituko duen 'Cookie-en ezarpenak' estekatik. Era berean, erabiltzaileak bere nabigatzailearen konfigurazioaren bidez kudeatu ditzake cookie hauek. Oro har, gailuan instalatutako cookieak baimendu, blokeatu edo ezabatu ditzakezu. Nabigatzaile bakoitzak bere cookie-ak nola kudeatu jakin behar duen dokumentazioa eskaintzen du. Hemen azpian, nabigatzaile ohikoena izaten diren dokumentazioen esteka ematen da:","Cookie-ak nola kudeatu","Datu Pertsonalen Babesa","Webgunearen datu pertsonalak biltzen dituenaren erantzuleak neurri tekniko eta antolakuntza beharrezkoak hartu ditu datu pertsonalak babesteko eta haien aldatzea, galera, tratamendua edo sarrera baimenik gabea izatea ekiditeko, teknologiaren egoera, gordeta dauden datuen natura eta haien eragina kontuan harturik. Hala ere, datu pertsonalen segurtasun absolutua ezin da bermatu Internet bidez transmititzen diren datuei dagokienez.","Erabiltzaileen Eskubideak","Erabiltzaileak eskubidea dauka:","Haren datu pertsonalak atzitzea eta nola tratatzen ari diren jakitea","Datuen pertsonalak zuzendu, baliogabekoak edo osatuak badira","Zuzenbidea datu pertsonalak ez direnean erabili behar direnean","Datu pertsonalen tratamendua murriztu, betiere une jakin batean","Datuen pertsonalak beste datu pertsonalak tratatzeko moldabide estrukturetan eta erabilizkoan eramatea","Datuen pertsonalen tratamenduari aurka egitea, betiere haien egoera bereziarekin lotuta dagoen arren","Eskubide hauek gauzatu ahal izango dira Pribatutasun Politika honetan emandako kontaktu datuei begiratuz.","Hirugarrenen Webguneetarako Estekak","Webguneak hirugarrenen webguneetara estekak izan ditzake. Datuak datu pertsonalak nola babesteko eta webgune horien edukia ez dago bermatuta datu pertsonalen babesa burutzeko ezarritako praktiken arabera. Erabiltzaileei aholkatzen zaie hirugarrenen webguneen pribatutasun politikak irakurri datu pertsonalak ematea baino lehen.","Cookie-en Politikaren Aldaketak","Webgunearen erantzuleak berak du Política de Cookies honetan aldaketak egin ditzakeela eskubidea. Erabiltzaileei gomendatzen zaie orri hau periodikoki ikustea eguneratutako informazioa izateko.","Kontaktua","Cookie-en Politika honi buruzko galdera edo iruzkin bat izanez gero, jar zaitez gurekin posta elektroniko helbide honen bidez: info@mycontacts.cloud.","Irakurri eta onartu dut"]};
  const SUPPORTED=new Set(Object.keys(EXP2));

  function normalizeLanguage(value){
    const raw=(value||"").toString().trim().toLowerCase();
    const short=raw.slice(0,2);
    return SUPPORTED.has(short)?short:'es';
  }

  function translateValue(base, lang){
    const source=EXP2.es;
    const target=EXP2[lang] || source;
    let idx=source.indexOf(base);
    if(idx!==-1) return target[idx] || base;

    const trimmedBase=base.trim();
    idx=source.findIndex(item => item.trim()===trimmedBase);
    if(idx!==-1){
      const translated=target[idx] || base;
      const hasTrailingSpace=/\s$/.test(base);
      const hasLeadingSpace=/^\s/.test(base);
      return (hasLeadingSpace?' ':'') + translated.trim() + (hasTrailingSpace?' ':'');
    }
    return base;
  }

  function translateNodes(lang){
    const nodes=document.querySelectorAll('h1,h2,h3,span');
    nodes.forEach((node)=>{
      if(!node.dataset.legalBase) node.dataset.legalBase=node.innerHTML;
      node.innerHTML=translateValue(node.dataset.legalBase, lang);
    });
  }

  function updateDocumentLanguage(lang){
    document.documentElement.lang=lang;
  }

  function cambiarTextoIdioma(value){
    const lang=normalizeLanguage(value || localStorage.getItem('idiomaPais') || navigator.language);
    translateNodes(lang);
    updateDocumentLanguage(lang);
    return lang;
  }

  window.cambiarTextoIdioma=cambiarTextoIdioma;
  document.addEventListener('DOMContentLoaded', function(){
    cambiarTextoIdioma();
  });
})();
